 {"id":"bd-um69","title":"Add baseline unit tests for ffs facade crate re-exports","description":"crates/ffs/src/lib.rs currently just re-exports ffs-core and has no crate-local tests. Add minimal smoke tests that prove key public API symbols/functions from the facade are reachable and callable (e.g., OpenOptions default, detect_filesystem error path, RepairPolicy default). Keep behavior unchanged and validate with rch-offloaded crate checks/tests.","status":"closed","priority":2,"issue_type":"task","created_at":"2026-02-26T01:55:00.029736372Z","created_by":"ubuntu","updated_at":"2026-02-26T02:02:50.681201826Z","closed_at":"2026-02-26T02:02:50.681180155Z","close_reason":"Added ffs facade smoke tests for key re-exports and validated with rch (fmt/check/clippy/test)","source_repo":".","compaction_level":0,"original_size":0,"labels":["facade","quality","tests"]}
