 {"id":"bd-unux","title":"Add unit tests for detect_filesystem_on_device and detect_filesystem_at_path","description":"detect_filesystem() with &[u8] is tested but the two path/device variants have zero direct tests. Add tests for: (1) device with valid ext4, (2) device with unrecognized image, (3) at_path with non-existent file, (4) at_path with valid ext4 fixture.","status":"closed","priority":2,"issue_type":"task","created_at":"2026-02-25T11:18:19.885724829Z","created_by":"ubuntu","updated_at":"2026-02-25T11:25:12.066490917Z","closed_at":"2026-02-25T11:25:12.066423922Z","source_repo":".","compaction_level":0,"original_size":0}
+{"id":"bd-upiwe","title":"ext4+btrfs mounted copy_file_range offset/overlap parity proof","description":"Queue-empty porting-to-rust fallback. Add mounted FUSE conformance coverage for direct copy_file_range(2) behavior on ext4 and btrfs: cross-file offset copies, same-inode non-overlap copies, zero-length no-op, and same-inode overlap EINVAL/no-drift. Update FEATURE_PARITY evidence.","status":"closed","priority":3,"issue_type":"task","assignee":"cod-fs","created_at":"2026-04-26T04:16:29.728300724Z","created_by":"ubuntu","updated_at":"2026-04-26T04:25:18.908683003Z","closed_at":"2026-04-26T04:25:18.906835685Z","close_reason":"Added ext4+btrfs mounted copy_file_range offset/overlap parity probes and updated parity evidence","source_repo":".","compaction_level":0,"original_size":0,"labels":["btrfs","ext4","fuse","parity","porting"]}
 {"id":"bd-uqfhd","title":"fuzz: add fuzz_por_authenticator target for PoR verification","description":"ffs_repair::por functions (compute_authenticator, verify_authenticator at por.rs:81,90) accept raw block data but lack fuzz coverage. Critical for data integrity verification.","status":"closed","priority":2,"issue_type":"task","created_at":"2026-04-22T12:18:25.655787699Z","created_by":"ubuntu","updated_at":"2026-04-23T00:49:45Z","closed_at":"2026-04-23T00:49:45Z","close_reason":"Implemented fuzz_por_authenticator with per-block/table consistency checks, key/index/block mutation rejection oracles, seeded corpus, and remote cargo check/clippy verification.","source_repo":".","compaction_level":0,"original_size":0}
 {"id":"bd-urvq","title":"Add btrfs COW parent-rewrite update success coverage","description":"Fallback testing-conformance round: add positive btrfs COW update coverage for a height-2 parent rewrite path. Existing coverage has leaf-root update success and parent-rewrite allocator-failure atomicity; this bead should prove the successful parent rewrite changes the root, preserves the previous root snapshot, keeps sorted range output stable, and updates only the target payload. Update conformance/COVERAGE.md accordingly.","status":"closed","priority":2,"issue_type":"task","assignee":"EmeraldCitadel","created_at":"2026-04-18T13:26:34.174141659Z","created_by":"ubuntu","updated_at":"2026-04-18T15:22:42.957011297Z","closed_at":"2026-04-18T15:22:42.954952579Z","close_reason":"Completed: added parent-rewrite success coverage and fixed synthetic tree-block CRC stamping regressions","source_repo":".","compaction_level":0,"original_size":0,"labels":["btrfs","testing"]}
